openscad:
case_diameter = 40; // [30:1:60]
case_thickness = 8; // [4:0.5:12]
dial_diameter = 36; // [25:1:55]
hand_length_hour = 10; // [5:0.5:20]
hand_length_minute = 14; // [8:0.5:25]
hand_length_second = 16; // [10:0.5:28]
date_window_size = 5; // [3:0.5:8]
marker_length = 2; // [1:0.5:4]
$fn = 60;

module watch_case() {
    color("silver")
    difference() {
        cylinder(d=case_diameter, h=case_thickness);
        translate([0,0,1])
            cylinder(d=dial_diameter+2, h=case_thickness);
    }
}

module dial() {
    color("white")
    cylinder(d=dial_diameter, h=1);
}

module hour_markers() {
    color("black")
    for (i = [0:11]) {
        rotate([0,0,i*30])
            translate([dial_diameter/2 - marker_length - 1, -0.4, 1.01])
                cube([marker_length, 0.8, 0.5]);
    }
}

module date_window() {
    color("white")
    translate([dial_diameter/2 - 8, 0, 1])
        cube([date_window_size, date_window_size, 1.5], center=true);
    color("black")
    translate([dial_diameter/2 - 8, 0, 1.5])
        linear_extrude(0.1)
            text("15", size=2.5, halign="center", valign="center");
}

module hour_hand() {
    color("black")
    translate([0,0,2])
        linear_extrude(1)
            polygon(points=[[0,-0.6],[hand_length_hour,0],[0,0.6]]);
}

module minute_hand() {
    color("black")
    translate([0,0,2.5])
        linear_extrude(1)
            polygon(points=[[0,-0.5],[hand_length_minute,0],[0,0.5]]);
}

module second_hand() {
    color("red")
    translate([0,0,3])
        linear_extrude(0.8)
            polygon(points=[[0,-0.3],[hand_length_second,0],[0,0.3]]);
}

module watch() {
    watch_case();
    translate([0,0,case_thickness-2])
        dial();
    translate([0,0,case_thickness-2])
        hour_markers();
    translate([0,0,case_thickness-2])
        date_window();
    rotate([0,0,30])
        hour_hand();
    rotate([0,0,150])
        minute_hand();
    rotate([0,0,270])
        second_hand();
}

watch();
